import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as d,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Автоматическое добавление тегов","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/auto-tagging.md","filePath":"ru-RU/Other/auto-tagging.md","lastUpdated":1781962217000}'),s={name:"ru-RU/Other/auto-tagging.md"};function n(c,a,l,p,r,g){return d(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="автоматическое-добавление-тегов" tabindex="-1">Автоматическое добавление тегов <a class="header-anchor" href="#автоматическое-добавление-тегов" aria-label="Permalink to &quot;Автоматическое добавление тегов&quot;">​</a></h1><p>Auto tagging настраивается здесь:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Функция автоматически генерирует теги изображений. Они полезны для поиска, фильтрации random image, публичной галереи и контроля доступа по возрастному рейтингу.</p><h2 id="что-умеет-auto-tagging" tabindex="-1">Что умеет Auto Tagging <a class="header-anchor" href="#что-умеет-auto-tagging" aria-label="Permalink to &quot;Что умеет Auto Tagging&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Возможность</th><th>Описание</th></tr></thead><tbody><tr><td>Генерация content tags</td><td>Добавляет теги для людей, сцен, объектов, художественного стиля и похожего визуального содержимого.</td></tr><tr><td>Генерация character tags</td><td>Полезно для anime-изображений и иллюстраций.</td></tr><tr><td>Добавление orientation tags</td><td>Добавляет <code>landscape</code>, <code>portrait</code> или <code>square</code>.</td></tr><tr><td>Добавление rating</td><td>Сохраняет результаты <code>G/S/Q/E</code> для general, sensitive, questionable или explicit content.</td></tr><tr><td>Auto-tag on upload</td><td>Новые изображения автоматически попадают в процесс тегирования.</td></tr><tr><td>Batch tagging</td><td>Добавляет теги к старым изображениям во всех папках или выбранных папках.</td></tr></tbody></table><h2 id="что-подготовить-сначала" tabindex="-1">Что подготовить сначала <a class="header-anchor" href="#что-подготовить-сначала" aria-label="Permalink to &quot;Что подготовить сначала&quot;">​</a></h2><p>Нужен как минимум один доступный URL Hugging Face Space.</p><p>Рекомендуемый вариант — сделать копию Space SmilingWolf <code>wd-tagger</code> в собственный аккаунт Hugging Face:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Публичный Space можно использовать для временного теста, но им пользуется много людей, поэтому возможны очереди, замедления или недоступность. Копия в своем аккаунте обычно стабильнее для постоянного auto tagging.</p><h2 id="дублирование-space-smilingwolf" tabindex="-1">Дублирование Space SmilingWolf <a class="header-anchor" href="#дублирование-space-smilingwolf" aria-label="Permalink to &quot;Дублирование Space SmilingWolf&quot;">​</a></h2><ol><li>Войдите в Hugging Face.</li><li>Откройте <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+t+`" alt="Публичный Space SmilingWolf" loading="lazy"></p><ol start="3"><li>Нажмите меню с тремя точками в правом верхнем углу.</li><li>Выберите <code>Duplicate this Space</code>.</li><li>Оставьте стандартное имя Space или задайте свое, например <code>wd-tagger</code>.</li><li>Установите visibility как <code>Public</code>. Public Spaces проще вызывать из ImgBed.</li><li>Сначала оставьте бесплатное hardware. Переходите на более мощное только при заметных очередях.</li><li>Создайте Space и дождитесь окончания build.</li></ol><p>После build откройте страницу своего Space. URL обычно выглядит так:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Скопируйте адрес из браузера и вставьте его в ImgBed в <code>Space URLs</code>.</p><h2 id="несколько-space-urls" tabindex="-1">Несколько Space URLs <a class="header-anchor" href="#несколько-space-urls" aria-label="Permalink to &quot;Несколько Space URLs&quot;">​</a></h2><p>Вводите по одному Space URL на строку.</p><table tabindex="0"><thead><tr><th>Значение</th><th>Описание</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Публичный Space SmilingWolf. Хорош для временного теста.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL страницы скопированного Space.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Ваш собственный дублированный Space.</td></tr></tbody></table><p>Можно указать несколько URL. ImgBed использует несколько Spaces вместе, что может ускорить обработку.</p><p>Если один Space временно недоступен, остальные могут продолжить работу.</p><h2 id="настроики" tabindex="-1">Настройки <a class="header-anchor" href="#настроики" aria-label="Permalink to &quot;Настройки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Рекомендация</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Введите подготовленные Space URLs. Нужен хотя бы один.</td></tr><tr><td>Target folder</td><td>Оставьте пустым для всех папок. Выбирайте папку только если нужно обработать конкретную директорию.</td></tr><tr><td>Recognition model</td><td>По умолчанию оставьте <code>wd-swinv2-tagger-v3</code>.</td></tr><tr><td>General tag threshold</td><td>Значение по умолчанию подходит большинству изображений. Ниже — больше тегов, выше — меньше.</td></tr><tr><td>Character tag threshold</td><td>Значение по умолчанию осторожное и помогает избегать неверных character tags.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>Сначала оставьте выключенным. Включайте, когда хотите, чтобы модель сама определяла число тегов.</td></tr><tr><td>Auto-tag on upload</td><td>Включите, если новые изображения должны получать теги автоматически.</td></tr><tr><td>Start tagging</td><td>Ручной batch tagging для старых изображений.</td></tr></tbody></table><h2 id="рекомендуемые-стартовые-значения" tabindex="-1">Рекомендуемые стартовые значения <a class="header-anchor" href="#рекомендуемые-стартовые-значения" aria-label="Permalink to &quot;Рекомендуемые стартовые значения&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Значение</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Сначала Off</td></tr><tr><td>Auto-tag on upload</td><td>Включить при необходимости</td></tr></tbody></table><p>Если тегов слишком много, немного поднимите general threshold.</p><p>Если тегов слишком мало, немного снизьте general threshold.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>Заполните <code>Space URLs</code>.</li><li>Выберите target folder.</li><li>Нажмите start tagging.</li><li>Дождитесь завершения прогресса.</li></ol><p>Если target folder пустой, ImgBed обрабатывает все папки.</p><p>Batch tagging лучше всего подходит для старых изображений. Для новых включите auto-tag on upload, чтобы не запускать процесс вручную каждый раз.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>После включения auto-tag on upload новые изображения автоматически вызывают настроенные <code>Space URLs</code>.</p><p>Это удобно для постоянного использования.</p><p>Если ваш Space стоит в очереди, сама загрузка все равно может завершиться первой, а тегирование продолжится после нее.</p><h2 id="какие-изображения-обрабатываются" tabindex="-1">Какие изображения обрабатываются <a class="header-anchor" href="#какие-изображения-обрабатываются" aria-label="Permalink to &quot;Какие изображения обрабатываются&quot;">​</a></h2><p>Auto tagging в основном обрабатывает файлы изображений.</p><p>Изображения, у которых уже есть полные tags, orientation, rating, width и height, пропускаются, чтобы не вызывать Space лишний раз.</p><p>ImgBed по возможности дополняет только недостающую информацию. Например, если не хватает только orientation, он попробует добавить orientation без полного content tag flow.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="зачем-дублировать-собственныи-space" tabindex="-1">Зачем дублировать собственный Space? <a class="header-anchor" href="#зачем-дублировать-собственныи-space" aria-label="Permalink to &quot;Зачем дублировать собственный Space?&quot;">​</a></h3><p>Публичные Spaces общие для многих пользователей. Собственный дублированный Space в основном использует только ваш ImgBed, поэтому он обычно быстрее и надежнее.</p><h3 id="space-постоянно-запускается" tabindex="-1">Space постоянно запускается <a class="header-anchor" href="#space-постоянно-запускается" aria-label="Permalink to &quot;Space постоянно запускается&quot;">​</a></h3><p>После первого создания или долгого простоя Space может требовать времени на запуск.</p><p>Сначала откройте страницу своего Space. Когда он нормально распознает изображение, вернитесь в ImgBed и запускайте тегирование.</p><h3 id="как-скопировать-space-url" tabindex="-1">Как скопировать Space URL? <a class="header-anchor" href="#как-скопировать-space-url" aria-label="Permalink to &quot;Как скопировать Space URL?&quot;">​</a></h3><p>Откройте страницу Hugging Face Space и скопируйте адрес из браузера.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="можно-ли-добавить-несколько-spaces" tabindex="-1">Можно ли добавить несколько Spaces? <a class="header-anchor" href="#можно-ли-добавить-несколько-spaces" aria-label="Permalink to &quot;Можно ли добавить несколько Spaces?&quot;">​</a></h3><p>Да. Вводите по одному Space URL на строку.</p><p>Несколько Spaces обрабатывают изображения вместе и полезны, когда файлов много.</p><h3 id="почему-теги-на-англииском" tabindex="-1">Почему теги на английском? <a class="header-anchor" href="#почему-теги-на-англииском" aria-label="Permalink to &quot;Почему теги на английском?&quot;">​</a></h3><p>Модели SmilingWolf возвращают английские теги. Это ожидаемое поведение.</p><p>Теги в основном используются для поиска, фильтров, random image API и публичной галереи.</p><h3 id="для-чего-нужны-rating-tags" tabindex="-1">Для чего нужны rating tags? <a class="header-anchor" href="#для-чего-нужны-rating-tags" aria-label="Permalink to &quot;Для чего нужны rating tags?&quot;">​</a></h3><p>Результаты rating работают вместе с access mode в Security Settings.</p><p>Например, когда доступ посетителей ограничен возрастным рейтингом, публичный просмотр и random image фильтруют изображения по этим правилам.</p><h2 id="короткии-сценарии" tabindex="-1">Короткий сценарий <a class="header-anchor" href="#короткии-сценарии" aria-label="Permalink to &quot;Короткий сценарий&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Войти в Hugging Face</span></span>
<span class="line"><span>-&gt; Открыть SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Дождаться build Space</span></span>
<span class="line"><span>-&gt; Скопировать Space URL</span></span>
<span class="line"><span>-&gt; Заполнить Space URLs в ImgBed</span></span>
<span class="line"><span>-&gt; Выбрать модель и thresholds</span></span>
<span class="line"><span>-&gt; Запустить tagging или включить auto-tag on upload</span></span></code></pre></div>`,61)])])}const m=e(s,[["render",n]]);export{b as __pageData,m as default};
